// Map domain names used in different state outlines to our bank keys
function normalizeBank(domain) {
  const d = domain.trim();
  // Direct match
  if (QUESTION_BANKS[d]) return d;
  // Partial matches
  const lower = d.toLowerCase();
  if (lower.includes("types of polic")) return "Types of Policies";
  if (lower.includes("rider") || lower.includes("provision") || lower.includes("exclusion")) return "Policy Riders, Provisions, Options, and Exclusions";
  if (lower.includes("general insurance") || lower.includes("insurance concept")) return "General Insurance Concepts";
  if (lower.includes("application") || lower.includes("underwriting") || lower.includes("delivering")) return "Completing the Application, Underwriting, and Delivering the Policy";
  if (lower.includes("tax")) return "Tax Treatment";
  if (lower.includes("state law") || lower.includes("regulation") || lower.includes("ethical")) return "State Law";
  if (lower.includes("underwriting") && !lower.includes("application")) return "Underwriting";
  if (lower.includes("life basics") || lower.includes("life insurance basics")) return "Life Basics";
  if (lower.includes("policy") && lower.includes("type")) return "Types of Policies";
  // Fallback: use the largest bank
  return "General Insurance Concepts";
}

// ═══════════════════════════════════════════════════════════════
//  MAIN: Extract varieties, build question sets, upload
// ═══════════════════════════════════════════════════════════════

async function main() {
  const states = stateFilter ? [stateFilter] : TARGET_STATES;
  let totalInserted = 0;
  let totalSkipped = 0;

  for (const sc of states) {
    const stateData = licensingData.states ? licensingData.states[sc] : licensingData[sc];
    if (!stateData || !Array.isArray(stateData.exam_varieties)) { console.log(`⚠️ No varieties data for ${sc}`); continue; }

    for (const variety of stateData.exam_varieties) {
      if (!variety.content_outline || variety.content_outline.length === 0) {
        console.log(`  ⚠️ ${sc} / ${variety.id} — no content outline, skipping`);
        continue;
      }

      const lineKey = (variety.applies_to_lines && variety.applies_to_lines[0]) || "life";

      console.log(`\n📋 ${sc} / ${variety.id} (${variety.name})`);
      console.log(`   Domains: ${variety.content_outline.length}, Target: 200 questions`);

      // Distribute 200 questions across domains proportional to weight_pct
      const totalWeight = variety.content_outline.reduce((s, d) => s + (d.weight_pct || 10), 0);
      const TARGET_TOTAL = 200;

      const questions = [];

      for (const domainEntry of variety.content_outline) {
        const domain = domainEntry.domain;
        const weight = domainEntry.weight_pct || 10;
        const count = Math.max(5, Math.round(TARGET_TOTAL * weight / totalWeight));
        const bankKey = normalizeBank(domain);
        const bank = QUESTION_BANKS[bankKey] || QUESTION_BANKS["General Insurance Concepts"];

        // Pick `count` questions, cycling through the bank
        for (let i = 0; i < count; i++) {
          const template = bank[i % bank.length];
          questions.push({
            state_code: sc,
            line: lineKey,
            variety_id: variety.id,
            domain: domain,
            stem: template.stem,
            options: template.options,
            correct_index: template.correct_index,
            explanation: template.explanation,
            difficulty: template.difficulty || "medium",
          });
        }
      }

        console.log(`   Generated: ${questions.length} questions`);

        if (DRY_RUN) {
          console.log(`   [DRY RUN] Would insert ${questions.length} rows`);
          totalSkipped += questions.length;
          continue;
        }

        // Batch insert into Supabase (50 at a time)
        const BATCH = 50;
        for (let i = 0; i < questions.length; i += BATCH) {
          const batch = questions.slice(i, i + BATCH);
          try {
            const resp = await fetch(`${SUPA_URL}/rest/v1/licensing_questions`, {
              method: "POST",
              headers: {
                apikey: SUPA_SRV,
                authorization: `Bearer ${SUPA_SRV}`,
                "content-type": "application/json",
                prefer: "return=minimal",
              },
              body: JSON.stringify(batch),
            });
            if (!resp.ok) {
              const err = await resp.text();
              console.error(`   ❌ Batch ${i}-${i+batch.length}: ${resp.status} ${err.slice(0, 200)}`);
            } else {
              totalInserted += batch.length;
              process.stdout.write(`   ✅ Inserted ${Math.min(i + BATCH, questions.length)}/${questions.length}\r`);
            }
          } catch (e) {
            console.error(`   ❌ Batch ${i}: ${e.message}`);
          }
        }
        console.log();
      }
    }

  console.log(`\n═══════════════════════════════════════`);
  console.log(`✅ Done. Inserted: ${totalInserted} questions, Skipped: ${totalSkipped}`);
}

main().catch(e => { console.error(e); process.exit(1); });
